const artistName = String($('When Executed by Another Workflow').first().json.artist_name || '').trim();
const candidates = $input.first().json.artists?.items || [];

if (!artistName) {
  return [{
    json: {
      error: 'artist_name is required',
      query_artist: '',
      matched_artist: null,
      albums_returned: 0,
      albums: [],
    },
  }];
}

if (!candidates.length) {
  return [{
    json: {
      error: 'No Spotify artist match found',
      query_artist: artistName,
      matched_artist: null,
      albums_returned: 0,
      albums: [],
    },
  }];
}

const target = artistName.toLowerCase();
const matched = candidates.find((artist) => artist.name.toLowerCase() === target) || candidates[0];

return [{
  json: {
    query_artist: artistName,
    matched_artist_id: matched.id,
    matched_artist: matched,
  },
}];

const base = $('Match Artist').first().json;
const items = $input.first().json.items || [];
const seen = new Set();
const outputs = [];

for (const album of items) {
  if (!album?.id || seen.has(album.id)) continue;
  seen.add(album.id);
  outputs.push({
    json: {
      query_artist: base.query_artist,
      matched_artist: base.matched_artist,
      album_id: album.id,
      simplified_album: album,
    },
  });
  if (outputs.length >= 10) break;
}

return outputs;

const prepared = $('Prepare Album Items').all().map((item) => item.json);
const first = prepared[0] || {};
const matched = first.matched_artist || {};

function parseLabel(text) {
  if (!text) return null;
  return text
    .replace(/^℗\s*/i, '')
    .replace(/^©\s*/i, '')
    .replace(/^\d{4}\s+/, '')
    .trim();
}

function isFullAlbum(payload) {
  return Boolean(payload?.id && payload?.album_type && !payload?.error);
}

const albums = $input.all().map((item, index) => {
  const prep = prepared[index] || first;
  const simplified = prep.simplified_album || {};
  const full = isFullAlbum(item.json) ? item.json : null;
  const source = full || simplified;
  const copyrights = full?.copyrights || [];
  const pLine = copyrights.find((entry) => entry.type === 'P');
  const cLine = copyrights.find((entry) => entry.type === 'C');

  return {
    album_id: source.id || prep.album_id,
    album_name: source.name || simplified.name,
    album_type: source.album_type || simplified.album_type,
    release_date: source.release_date || simplified.release_date,
    total_tracks: source.total_tracks ?? simplified.total_tracks,
    spotify_url: source.external_urls?.spotify || simplified.external_urls?.spotify || null,
    label_from_p_line: parseLabel(pLine?.text),
    p_line: pLine?.text || null,
    c_line: cLine?.text || null,
    copyrights,
  };
});

return [{
  json: {
    query_artist: first.query_artist,
    matched_artist: {
      id: matched.id,
      name: matched.name,
      genres: matched.genres || [],
      popularity: matched.popularity,
      spotify_url: matched.external_urls?.spotify || null,
    },
    albums_returned: albums.length,
    albums,
  },
}];

const item = $input.first().json;

return [{
  json: {
    query_artist: item.query_artist ?? null,
    error: item.error || 'No Spotify artist match found',
    matched_artist: item.matched_artist ?? null,
    albums_returned: 0,
    albums: [],
  },
}];
